import React, { useEffect, useState } from "react";
import { getFreelancerDashboard } from "../../api/api";
import { useNavigate } from "react-router-dom";

const formatDate = (d) => d ? new Date(d).toLocaleDateString("en-IN", {
  day: "2-digit", month: "short", year: "numeric"
}) : "";

const FreelancerDashboard = () => {
  const user = JSON.parse(localStorage.getItem("user") || "{}");
  const navigate = useNavigate();
  const [data, setData]     = useState({ activeProjects: 0, pendingProposals: 0, projects: [] });
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const load = async () => {
      try {
        const res = await getFreelancerDashboard();
        setData(res.data);
      } catch (err) { console.error(err); }
      setLoading(false);
    };
    load();
  }, []);

  if (loading) return <div className="text-center py-16 text-gray-400">Loading...</div>;

  return (
    <div className="bg-gray-50 min-h-screen p-8">
      <div className="max-w-5xl mx-auto">

        {/* HEADER */}
        <div className="mb-8">
          <h1 className="text-2xl font-bold text-gray-800">Welcome back, {user.name} 👋</h1>
          <p className="text-gray-500 mt-1 text-sm">Here's your freelancing overview</p>
        </div>

        {/* STAT CARDS — 4 cards */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
          <div className="bg-white rounded-xl p-5 shadow-sm border-l-4 border-blue-500">
            <p className="text-xs text-gray-500 mb-1">Applied Projects</p>
            <h2 className="text-3xl font-bold text-blue-600">{data.activeProjects}</h2>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border-l-4 border-yellow-500">
            <p className="text-xs text-gray-500 mb-1">Total Proposals</p>
            <h2 className="text-3xl font-bold text-yellow-600">{data.pendingProposals}</h2>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border-l-4 border-green-500">
            <p className="text-xs text-gray-500 mb-1">Accepted</p>
            <h2 className="text-3xl font-bold text-green-600">
              {data.projects?.filter(p => p.proposal_status === "accepted").length || 0}
            </h2>
          </div>
          <div className="bg-white rounded-xl p-5 shadow-sm border-l-4 border-teal-500">
            <p className="text-xs text-gray-500 mb-1">Account Type</p>
            <h2 className="text-lg font-bold text-teal-600 capitalize mt-1">{user.role}</h2>
          </div>
        </div>

        {/* PROJECTS YOU APPLIED TO */}
        <div className="bg-white rounded-xl shadow-sm border border-gray-100">
          <div className="flex justify-between items-center p-5 border-b border-gray-100">
            <h2 className="font-bold text-gray-700">Projects You Applied To</h2>
            <button onClick={() => navigate("/freelancer/find-projects")}
              className="text-sm text-teal-600 hover:text-teal-700 font-medium">
              Browse Projects →
            </button>
          </div>

          {data.projects?.length === 0 ? (
            <div className="text-center py-16">
              <div className="text-5xl mb-3">🔍</div>
              <p className="text-gray-400 mb-4">No projects applied yet.</p>
              <button onClick={() => navigate("/freelancer/find-projects")}
                className="bg-teal-600 text-white px-5 py-2 rounded-lg text-sm font-medium">
                Find Projects
              </button>
            </div>
          ) : (
            <div className="divide-y divide-gray-50">
              {data.projects.map((p) => (
                <div key={p.id} className="flex justify-between items-center px-5 py-4 hover:bg-gray-50 transition">
                  <div className="flex-1 min-w-0">
                    <h3 className="font-semibold text-gray-800 truncate">{p.title}</h3>
                    <p className="text-sm text-gray-400 truncate mt-0.5">{p.description?.slice(0, 80)}...</p>
                    <div className="flex gap-4 mt-1 text-xs text-gray-400">
                      <span>Budget: ₹{p.budget}</span>
                      {p.my_bid && <span className="text-teal-600 font-semibold">Your Bid: ₹{p.my_bid}</span>}
                      {p.deadline && <span>📅 {formatDate(p.deadline)}</span>}
                    </div>
                  </div>
                  {p.proposal_status && (
                    <span className={`ml-4 px-3 py-1 rounded-full text-xs font-semibold capitalize flex-shrink-0 ${
                      p.proposal_status === "accepted" ? "bg-green-100 text-green-700" :
                      p.proposal_status === "rejected" ? "bg-red-100 text-red-600" :
                      "bg-yellow-100 text-yellow-700"
                    }`}>
                      {p.proposal_status}
                    </span>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>

      </div>
    </div>
  );
};

export default FreelancerDashboard;
